def analyze_organization(employees):
    """
    Analyzes the organizational power structure and resolves the following:
    1. Pecking Order Level: For each employee, determine their stratum in the hierarchy.
    2. Subordinate Enumeration: For each employee, calculate the total number of subordinates under them, including collateral subordinates.
    3. Manager Chain: For each employee, list their chain of managers upward to the CEO.

    Args:
        employees: A list of dictionaries, where each dictionary represents an employee
                   and contains 'employee_id', 'employee_name', and 'manager_id'.

    Returns:
        A tuple containing three lists:
        - hierarchy_levels: A list of dictionaries, where each dictionary contains 'employee_id', 'employee_name', and 'level'.
        - subordinate_counts: A list of dictionaries, where each dictionary contains 'employee_id', 'employee_name', and 'subordinate_count'.
        - manager_chains: A list of dictionaries, where each dictionary contains 'employee_id', 'employee_name', and 'manager_chain'.
    """

    employee_map = {emp['employee_id']: emp for emp in employees}
    ceo_id = next((emp['employee_id'] for emp in employees if emp['manager_id'] == 0), None)

    hierarchy_levels = []
    subordinate_counts = {}
    manager_chains = {}

    def calculate_level(employee_id):
        if employee_id == ceo_id:
            return 1
        employee = employee_map[employee_id]
        return calculate_level(employee['manager_id']) + 1

    def calculate_subordinates(employee_id):
        count = 0
        for emp_id, emp in employee_map.items():
            if emp['manager_id'] == employee_id:
                count += 1 + calculate_subordinates(emp_id)
        return count

    def get_manager_chain(employee_id):
        chain = []
        current_id = employee_id
        while current_id != ceo_id:
            employee = employee_map[current_id]
            manager_id = employee['manager_id']
            manager = employee_map[manager_id]
            chain.insert(0, manager['employee_name'])
            current_id = manager_id
        return '>'.join(chain) if chain else "None" if employee_id == ceo_id else employee_map[employee_id]['employee_name'] if employee_map[employee_id]['manager_id'] == ceo_id else employee_map[employee_map[employee_id]['manager_id']]['employee_name'] + ">" + employee_map[ceo_id]['employee_name'] if employee_map[employee_id]['manager_id'] != 0 else employee_map[ceo_id]['employee_name']

    for employee in employees:
        employee_id = employee['employee_id']
        employee_name = employee['employee_name']

        level = calculate_level(employee_id)
        hierarchy_levels.append({'employee_id': employee_id, 'employee_name': employee_name, 'level': level})

        subordinate_count = calculate_subordinates(employee_id)
        subordinate_counts[employee_id] = {'employee_id': employee_id, 'employee_name': employee_name, 'subordinate_count': subordinate_count}

        manager_chain = get_manager_chain(employee_id)
        manager_chains[employee_id] = {'employee_id': employee_id, 'employee_name': employee_name, 'manager_chain': manager_chain}

    return hierarchy_levels, list(subordinate_counts.values()), list(manager_chains.values())


if __name__ == '__main__':
    employees = [
        {'employee_id': 1, 'employee_name': 'Alice', 'manager_id': 0},
        {'employee_id': 2, 'employee_name': 'Bob', 'manager_id': 1},
        {'employee_id': 3, 'employee_name': 'Charlie', 'manager_id': 1},
        {'employee_id': 4, 'employee_name': 'David', 'manager_id': 2},
        {'employee_id': 5, 'employee_name': 'Eve', 'manager_id': 2},
        {'employee_id': 6, 'employee_name': 'Frank', 'manager_id': 3}
    ]

    hierarchy_levels, subordinate_counts, manager_chains = analyze_organization(employees)

    print("Pecking Order Level:")
    for level_info in hierarchy_levels:
        print(f"employee_id: {level_info['employee_id']}, employee_name: {level_info['employee_name']}, level: {level_info['level']}")

    print("\nSubordinate Count:")
    for count_info in subordinate_counts:
